const { Pool } = require('pg');

// Create a new pool instance with the PostgreSQL connection details
const pool = new Pool({
  user: 'postgres',
  host: 'localhost',
  database: 'your_database_name',
  password: 'your_password',
  port: 5432,
});

// Function to get all records from a table
async function getAll(tableName) {
  const queryText = `SELECT * FROM ${tableName}`;
  try {
    const res = await pool.query(queryText);
    return res.rows;
  } catch (err) {
    console.error(err.stack);
    throw err;
  }
}

// Function to get a single record by ID from a table
async function getById(tableName, id) {
  const queryText = `SELECT * FROM ${tableName} WHERE id = $1`;
  try {
    const res = await pool.query(queryText, [id]);
    return res.rows[0];
  } catch (err) {
    console.error(err.stack);
    throw err;
  }
}

// Function to create a new record in a table
async function create(tableName, data) {
  const columns = Object.keys(data).join(', ');
  const values = Object.values(data).map((value) => `$${Object.values(data).indexOf(value) + 1}`).join(', ');
  const queryText = `INSERT INTO ${tableName} (${columns}) VALUES (${values}) RETURNING *`;
  try {
    const res = await pool.query(queryText, Object.values(data));
    return res.rows[0];
  } catch (err) {
    console.error(err.stack);
    throw err;
  }
}

// Function to update a record in a table
async function update(tableName, id, data) {
  const setClause = Object.keys(data).map((key) => `${key} = $${Object.values(data).indexOf(data[key]) + 2}`).join(', ');
  const queryText = `UPDATE ${tableName} SET ${setClause} WHERE id = $1 RETURNING *`;
  try {
    const res = await pool.query(queryText, [id, ...Object.values(data)]);
    return res.rows[0];
  } catch (err) {
    console.error(err.stack);
    throw err;
  }
}

// Function to delete a record from a table
async function deleteRecord(tableName, id) {
  const queryText = `DELETE FROM ${tableName} WHERE id = $1 RETURNING *`;
  try {
    const res = await pool.query(queryText, [id]);
    return res.rows[0];
  } catch (err) {
    console.error(err.stack);
    throw err;
  }
}

// Example usage
(async () => {
  try {
    // Create a new record in the 'users' table
    const newUser = await create('users', { name: 'John Doe', email: 'john@example.com' });
    console.log('New user created:', newUser);

    // Get all records from the 'users' table
    const users = await getAll('users');
    console.log('All users:', users);

    // Update a record in the 'users' table
    const updatedUser = await update('users', newUser.id, { name: 'Jane Doe' });
    console.log('Updated user:', updatedUser);

    // Get a single record by ID from the 'users' table
    const userById = await getById('users', newUser.id);
    console.log('User by ID:', userById);

    // Delete a record from the 'users' table
    const deletedUser = await deleteRecord('users', newUser.id);
    console.log('Deleted user:', deletedUser);
  } catch (err) {
    console.error(err);
  } finally {
    await pool.end();
  }
})();